"use client";

import { useEffect, useRef, useState, useCallback } from "react";
import { io, Socket } from "socket.io-client";
import Peer from "simple-peer";

type Status = "idle" | "waiting" | "connected";

interface Message {
  text: string;
  self: boolean;
}

interface UseSocketReturn {
  status: Status;
  onlineCount: number;
  messages: Message[];
  localStream: MediaStream | null;
  remoteStream: MediaStream | null;
  findMatch: () => void;
  next: () => void;
  sendMessage: (text: string) => void;
  report: (reason: string) => void;
  switchCamera: () => void;
}

const SOCKET_URL =
  process.env.NEXT_PUBLIC_SOCKET_URL || "http://localhost:4000";

export function useSocket(interests: string[]): UseSocketReturn {
  const socketRef = useRef<Socket | null>(null);
  const peerRef = useRef<Peer.Instance | null>(null);
  const localStreamRef = useRef<MediaStream | null>(null);
  const currentCameraIndex = useRef<number>(0);

  const [status, setStatus] = useState<Status>("idle");
  const [onlineCount, setOnlineCount] = useState<number>(0);
  const [messages, setMessages] = useState<Message[]>([]);
  const [localStream, setLocalStream] = useState<MediaStream | null>(null);
  const [remoteStream, setRemoteStream] = useState<MediaStream | null>(null);

  // Initialise socket once
  useEffect(() => {
    const socket = io(SOCKET_URL, { transports: ["websocket"] });
    socketRef.current = socket;

    socket.on("online-count", (count: number) => setOnlineCount(count));

    socket.on("matched", ({ initiator }: { initiator: boolean }) => {
      setStatus("connected");
      setMessages([]);
      createPeer(initiator);
    });

    socket.on("signal", (data: Peer.SignalData) => {
      peerRef.current?.signal(data);
    });

    socket.on("chat-message", (text: string) => {
      setMessages((prev) => [...prev, { text, self: false }]);
    });

    socket.on("partner-left", () => {
      destroyPeer();
      setStatus("idle");
      setRemoteStream(null);
      setMessages([]);
    });

    return () => {
      socket.disconnect();
      destroyPeer();
      stopLocalStream();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  function destroyPeer() {
    peerRef.current?.destroy();
    peerRef.current = null;
  }

  function stopLocalStream() {
    localStreamRef.current?.getTracks().forEach((t) => t.stop());
    localStreamRef.current = null;
    setLocalStream(null);
  }

  async function getLocalStream(): Promise<MediaStream> {
    if (localStreamRef.current) return localStreamRef.current;
    const stream = await navigator.mediaDevices.getUserMedia({
      video: true,
      audio: true,
    });
    localStreamRef.current = stream;
    setLocalStream(stream);
    return stream;
  }

  function createPeer(initiator: boolean) {
    getLocalStream()
      .then((stream) => {
        const peer = new Peer({ initiator, trickle: true, stream });

        peer.on("signal", (data) => {
          socketRef.current?.emit("signal", data);
        });

        peer.on("stream", (remoteStream) => {
          setRemoteStream(remoteStream);
        });

        peer.on("error", (err) => {
          console.error("Peer error:", err);
          destroyPeer();
          setStatus("idle");
        });

        peer.on("close", () => {
          setRemoteStream(null);
          setStatus("idle");
        });

        peerRef.current = peer;
      })
      .catch((err) => {
        console.error("Failed to get local stream:", err);
      });
  }

  const findMatch = useCallback(() => {
    setStatus("waiting");
    setMessages([]);
    setRemoteStream(null);
    destroyPeer();
    socketRef.current?.emit("find-match", { interests });
  }, [interests]);

  const next = useCallback(() => {
    destroyPeer();
    setStatus("waiting");
    setMessages([]);
    setRemoteStream(null);
    socketRef.current?.emit("next", { interests });
  }, [interests]);

  const sendMessage = useCallback((text: string) => {
    socketRef.current?.emit("chat-message", text);
    setMessages((prev) => [...prev, { text, self: true }]);
  }, []);

  const report = useCallback((reason: string) => {
    socketRef.current?.emit("report", { reason });
  }, []);

  const switchCamera = useCallback(async () => {
    try {
      const devices = await navigator.mediaDevices.enumerateDevices();
      const videoDevices = devices.filter((d) => d.kind === "videoinput");
      if (videoDevices.length < 2) return;

      currentCameraIndex.current =
        (currentCameraIndex.current + 1) % videoDevices.length;
      const deviceId = videoDevices[currentCameraIndex.current].deviceId;

      const newStream = await navigator.mediaDevices.getUserMedia({
        video: { deviceId: { exact: deviceId } },
        audio: true,
      });

      // Replace video track in the peer connection
      const oldVideoTrack = localStreamRef.current?.getVideoTracks()[0];
      const newVideoTrack = newStream.getVideoTracks()[0];

      if (peerRef.current && oldVideoTrack) {
        // @ts-ignore — simple-peer internal
        const sender = peerRef.current._pc
          ?.getSenders()
          .find((s: RTCRtpSender) => s.track?.kind === "video");
        sender?.replaceTrack(newVideoTrack);
      }

      // Stop old stream tracks
      localStreamRef.current?.getTracks().forEach((t) => t.stop());
      localStreamRef.current = newStream;
      setLocalStream(newStream);
    } catch (err) {
      console.error("switchCamera error:", err);
    }
  }, []);

  return {
    status,
    onlineCount,
    messages,
    localStream,
    remoteStream,
    findMatch,
    next,
    sendMessage,
    report,
    switchCamera,
  };
}
